// Publish the live parsed sample to LAN via MQTT
msg.topic = "greenhouse/data/live";
// msg.payload is already the parsed object from Parse sensor line
return msg;

let p = msg.payload;

// Ensure timestamp exists (epoch ms)
if (!p.ts) {
    p.ts = Date.now();
}

// Preserve original decoded sample for dashboard/other branches
msg.data = p;

// Build parameterized SQL
msg.topic = `
INSERT INTO greenhouse_samples
(ts, t1, t2, tavg, h1, h2, havg, soil, lux, louvre_pct, louvre_state)
VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
`;

msg.payload = [
  p.ts,
  p.t1 ?? null,
  p.t2 ?? null,
  p.tavg ?? null,
  p.h1 ?? null,
  p.h2 ?? null,
  p.havg ?? null,
  p.soil ?? null,
  p.lux ?? null,
  p.louvre_pct ?? null,
  p.louvre_state ?? null
];

return msg;

// Expect rows from SQLite
if (!Array.isArray(msg.payload) || msg.payload.length === 0) {
    return null;
}

// Take the newest row
const row = msg.payload[0];

// Set MQTT topic
msg.topic = "greenhouse/data/latest";

// Publish JSON object
msg.payload = row;

return msg;

// if msg.payload is already an object
