let s = msg.payload.louvre_state;
let pct = msg.payload.louvre_pct;

if (s === "opening") {
    msg.payload = "🟢 Opening";
} else if (s === "closing") {
    msg.payload = "🟠 Closing";
} else if (pct <= 5) {
    msg.payload = "⚫ Closed";
} else if (pct >= 95) {
    msg.payload = "🟢 Open";
} else {
    msg.payload = "🟡 Stopped @ " + Math.round(pct) + "%";
}

return msg;

// Guard greenhouse payload
// Purpose:
// 1) Reject malformed payloads
// 2) Hold last known good payload
// 3) Prevent one bad lux/glitch sample from zeroing all gauges
// 4) Preserve fault metadata so faults can be shown on the dashboard

let p = msg.payload;
let last = context.get("lastGood") || null;
let lastGoodLux = context.get("lastGoodLux");

function isNum(v) {
    return typeof v === "number" && isFinite(v);
}

function cloneObj(obj) {
    return JSON.parse(JSON.stringify(obj));
}

function addFaultMeta(target, source) {
    if (!target || typeof target !== "object") {
        target = {};
    }

    if (source && typeof source === "object") {
        target.faults = source.faults || {};
        target.fault_count = source.fault_count || 0;
        target.system_fault = source.system_fault || 0;
        target.missing_fields = source.missing_fields || "";
    } else {
        target.faults = {};
        target.fault_count = 0;
        target.system_fault = 0;
        target.missing_fields = "";
    }

    return target;
}

// Payload must be an object
if (typeof p !== "object" || p === null) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

// Required numeric fields
let required = [
    "t1", "t2", "tavg",
    "h1", "h2", "havg",
    "soil", "lux",
    "louvre_pct", "fan_pct"
];

for (let i = 0; i < required.length; i++) {
    let k = required[i];
    if (!isNum(p[k])) {
        if (last) {
            msg.payload = addFaultMeta(cloneObj(last), p);
            return msg;
        }
        return null;
    }
}

// Optional string/state field check
if (typeof p.louvre_state !== "string") {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

// Range checks for temperatures
if (p.t1 < -40 || p.t1 > 150) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

if (p.t2 < -40 || p.t2 > 150) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

if (p.tavg < -40 || p.tavg > 150) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

// Range checks for humidity
if (p.h1 < 0 || p.h1 > 100) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

if (p.h2 < 0 || p.h2 > 100) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

if (p.havg < 0 || p.havg > 100) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

// Soil range check
if (p.soil < 0 || p.soil > 100) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

// Lux range check
// If lux is invalid, keep the last known good lux for the gauge,
// but preserve the incoming fault metadata.
if (p.lux < 0 || p.lux > 150000) {
    let out;

    if (last) {
        out = cloneObj(last);
    } else {
        out = cloneObj(p);
    }

    if (isNum(lastGoodLux)) {
        out.lux = lastGoodLux;
    }

    msg.payload = addFaultMeta(out, p);
    return msg;
}

// Louvre/fan range checks
if (p.louvre_pct < 0 || p.louvre_pct > 100) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

if (p.fan_pct < 0 || p.fan_pct > 100) {
    if (last) {
        msg.payload = addFaultMeta(cloneObj(last), p);
        return msg;
    }
    return null;
}

// Lux deglitch:
// If lux suddenly drops to 0 from a normal reading, treat it as a glitch
if (last && isNum(last.lux)) {
    if (p.lux === 0 && last.lux > 5) {
        let out = cloneObj(last);
        msg.payload = addFaultMeta(out, p);
        return msg;
    }
}

// Save good payload
context.set("lastGood", cloneObj(p));

if (isNum(p.lux) && p.lux >= 0 && p.lux <= 150000) {
    context.set("lastGoodLux", p.lux);
}

msg.payload = p;
return msg;

let on = msg.payload.lightOn;

if (on === true) {
    msg.payload = "🟢 Grow Lights On";
} else {
    msg.payload = "⚫ Grow Lights Off";
}

return msg;

let p = msg.payload || {};

let required = [
    "t1",
    "t2",
    "tavg",
    "h1",
    "h2",
    "havg",
    "soil",
    "lux",
    "louvre_pct",
    "louvre_state",
    "fan_pct",
    "lightOn"
];

let faults = {};
let missing = [];

function isNum(v) {
    return typeof v === "number" && isFinite(v);
}

// Step 1: missing field detection
required.forEach(name => {
    if (!(name in p) || p[name] === null || p[name] === "") {
        faults[name] = "MISSING";
        missing.push(name);
    }
});

// Step 2: invalid value detection
if ("lux" in p && isNum(p.lux) && p.lux < 0) {
    faults.lux = "INVALID";
}

if ("soil" in p && isNum(p.soil) && (p.soil < 0 || p.soil > 100)) {
    faults.soil = "INVALID";
}

if ("louvre_pct" in p && isNum(p.louvre_pct) && (p.louvre_pct < 0 || p.louvre_pct > 100)) {
    faults.louvre_pct = "INVALID";
}

if ("fan_pct" in p && isNum(p.fan_pct) && (p.fan_pct < 0 || p.fan_pct > 100)) {
    faults.fan_pct = "INVALID";
}

if ("h1" in p && isNum(p.h1) && (p.h1 < 0 || p.h1 > 100)) {
    faults.h1 = "INVALID";
}

if ("h2" in p && isNum(p.h2) && (p.h2 < 0 || p.h2 > 100)) {
    faults.h2 = "INVALID";
}

if ("havg" in p && isNum(p.havg) && (p.havg < 0 || p.havg > 100)) {
    faults.havg = "INVALID";
}

// Step 3: soil erratic behavior detection
// If soil jumps too far between consecutive samples, flag it.
// This catches floating analog input behavior when the sensor is removed.
let lastSoil = context.get("lastSoil");
let soilJumpThreshold = 40;

if ("soil" in p && isNum(p.soil)) {
    if (isNum(lastSoil)) {
        if (Math.abs(p.soil - lastSoil) > soilJumpThreshold) {
            faults.soil = "FLOATING";
        }
    }
    context.set("lastSoil", p.soil);
}

p.faults = faults;
p.fault_count = Object.keys(faults).length;
p.system_fault = p.fault_count > 0 ? 1 : 0;
p.missing_fields = missing.join(",");

msg.payload = p;
return msg;

let p = msg.payload || {};
let faults = p.faults || {};
let hasFault = p.system_fault === 1;

// NEW: read comm watchdog state
