// Build list of faults
let faultList = [];

// Add existing sensor faults (your original behavior)
if (hasFault) {
    let keys = Object.keys(faults);

    if (keys.length) {
        faultList = faultList.concat(
            keys.map(k => k + ": " + faults[k])
        );
    } else {
        faultList.push("FAULT ACTIVE");
    }
}

// NEW: add comm fault
if (commFault === 1) {
